// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

// Structure to represent an item
typedef struct Item {
    long long price;
    struct Item* next;
} Item;

// Structure to represent a store
typedef struct Store {
    Item* head;
    long long conservationFee;
} Store;

// Function to add an item to a store
void addItem(Store* store, long long price) {
    Item* newItem = (Item*) malloc(sizeof(Item));
    newItem->price = price;
    newItem->next = store->head;
    store->head = newItem;
}

// Function to update the conservation fee for a store
void updateConservationFee(Store* store, long long fee) {
    store->conservationFee += fee;
}

// Function to find the maximum price of an item in a store plus the conservation fee
long long findMaxPrice(Store* store) {
    long long maxPrice = LLONG_MIN;
    Item* current = store->head;
    while (current != NULL) {
        maxPrice = (maxPrice > current->price) ? maxPrice : current->price;
        current = current->next;
    }
    return maxPrice + store->conservationFee;
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Store* stores = (Store*) malloc(N * sizeof(Store));
    for (int i = 0; i < N; i++) {
        stores[i].head = NULL;
        stores[i].conservationFee = 0;
    }
    for (int i = 0; i < M; i++) {
        int eventType;
        scanf("%d", &eventType);
        if (eventType == 1) {
            int u, v;
            long long a, b;
            scanf("%d %d %lld %lld", &u, &v, &a, &b);
            for (int j = u - 1; j < v; j++) {
                addItem(&stores[j], a * j + b);
            }
        } else if (eventType == 2) {
            int u, v;
            long long a, b;
            scanf("%d %d %lld %lld", &u, &v, &a, &b);
            for (int j = u - 1; j < v; j++) {
                updateConservationFee(&stores[j], a * j + b);
            }
        } else {
            int i;
            scanf("%d", &i);
            long long maxPrice = findMaxPrice(&stores[i - 1]);
            if (maxPrice == LLONG_MIN) {
                printf("NA\n");
            } else {
                printf("%lld\n", maxPrice);
            }
        }
    }
    return 0;
}

